function Home() {
  return (
    <div
      className="w-full h-[100vh] flex items-center justify-center"
      style={{
        backgroundImage: "url('/fondo6.jpg')",
        backgroundSize: 'cover',
        backgroundPosition: 'center',
      }}
    >
      <div className="flex flex-col items-center">
        <h1 className="text-white text-4xl md:text-6xl font-bold text-center">
          ¡Los invitamos a festejar nuestra boda!
        </h1>
        <h2 className="text-white text-4xl md:text-6xl font-bold text-center">
          Anto & Kevin
        </h2>
        <Link
          to="/confirmar-asistencia" // Ruta hacia el componente ConfirmAttendance
          className="text-white text-xl mt-4 underline hover:text-gray-300"
        >
          Confirmar asistencia
        </Link>
      </div>
    </div>
  );
}

export default Home;
